code = """import pandas as pd
businesses_credit_cards = locals()['var_function-call-17655127689096567034']
df = pd.DataFrame(businesses_credit_cards)

# Extract categories from the 'description' field
def extract_categories(description):
    if description:
        # Categories are usually listed after 'services in ' or 'services and products in the fields of '
        # Or sometimes after 'premier destination for ' or 'wide range of services, including '
        if 'services in ' in description:
            categories_str = description.split('services in ')[-1]
        elif 'services and products in the fields of ' in description:
            categories_str = description.split('services and products in the fields of ')[-1]
        elif 'premier destination for ' in description:
            categories_str = description.split('premier destination for ')[-1]
        elif 'wide range of services, including ' in description:
            categories_str = description.split('wide range of services, including ')[-1]
        else:
            return []

        # Split by comma and clean up, then remove '.' at the end if exists
        categories = [cat.strip().replace('.', '') for cat in categories_str.split(',')]
        return categories
    return []

df['categories'] = df['description'].apply(extract_categories)

# Explode the categories list to have one row per category
df_exploded = df.explode('categories')

# Count businesses per category
category_counts = df_exploded['categories'].value_counts().reset_index()
category_counts.columns = ['category', 'business_count']

print('__RESULT__:')
print(category_counts.to_json(orient='records'))"""

